import React from "react";
import { BrowserRouter, Routes, Route, useNavigate } from "react-router-dom";
import "./App.css";

function Login() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">
        <div className="top-shape"></div>

        <h1>Welcome</h1>
        <p className="subtitle">Sign in to continue</p>

        <div className="form">
          <label>Email</label>
          <input type="email" placeholder="your email address goes here" />

          <label>Password</label>
          <input type="password" placeholder="••••••••" />

          <p className="forgot" onClick={() => navigate("/forgot-password")}>
            Forgot Password?
          </p>

          <button>Sign in</button>

          <p className="or">OR</p>
          <p>Connect with</p>
          <div className="socials">G | f</div>

          <p className="bottom-text">
            Don’t have Account?{" "}
            <span onClick={() => navigate("/register")}>Sign up</span>
          </p>
        </div>
      </div>
    </div>
  );
}

function Register() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">
        <div className="top-shape"></div>

        <h1>Create Account</h1>

        <div className="form">
          <label>Name</label>
          <input type="text" placeholder="your full name goes here" />

          <label>Email</label>
          <input type="email" placeholder="your email address goes here" />

          <label>Phone</label>
          <input type="text" placeholder="your phone number here" />

          <label>Password</label>
          <input type="password" placeholder="••••••••" />

          <button>Sign up</button>

          <p className="or">OR</p>
          <p>Create account with</p>
          <div className="socials">G | f</div>

          <p className="bottom-text">
            Already Have an account?{" "}
            <span onClick={() => navigate("/")}>Sign in</span>
          </p>
        </div>
      </div>
    </div>
  );
}

function ForgotPassword() {
  const navigate = useNavigate();

  return (
    <div className="page">
      <div className="phone-card">
        <div className="top-shape"></div>

        <h1>Reset Password</h1>
        <p className="subtitle">Enter your email to reset password</p>

        <div className="form">
          <label>Email</label>
          <input type="email" placeholder="your email address goes here" />

          <button onClick={() => alert("Password reset link sent!")}>
            Send Reset Link
          </button>

          <p className="bottom-text">
            Remember password?{" "}
            <span onClick={() => navigate("/")}>Sign in</span>
          </p>
        </div>
      </div>
    </div>
  );
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/" element={<Login />} />
        <Route path="/register" element={<Register />} />
        <Route path="/forgot-password" element={<ForgotPassword />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
